CREATE TABLE t_p30447770_bloodytear_messaging.users (id SERIAL PRIMARY KEY, username VARCHAR(50) UNIQUE NOT NULL, email VARCHAR(255) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, display_name VARCHAR(100) NOT NULL, avatar_url TEXT, status VARCHAR(255) DEFAULT 'online', online_status VARCHAR(20) DEFAULT 'offline', last_seen TIMESTAMP DEFAULT NOW(), created_at TIMESTAMP DEFAULT NOW())
